## 💡 核心改进方案

### 🚀 **方案 1: 实现事件驱动架构** (P0 - 最高优先级)

#### 架构设计

```typescript
// ==================== 第一步: 创建事件总线 ====================
// src/event-bus.ts
import { EventEmitter } from 'events'

export enum AgentEvent {
  ITERATION_STARTED = 'iteration.started',
  ITERATION_COMPLETED = 'iteration.completed',
  ITERATION_FAILED = 'iteration.failed',
  AGENT_STARTED = 'agent.started',
  AGENT_PROGRESS = 'agent.progress',
  AGENT_COMPLETED = 'agent.completed',
  SYSTEM_METRICS = 'system.metrics'
}

export class EventBus extends EventEmitter {
  private static instance: EventBus

  static getInstance() {
    if (!this.instance) {
      this.instance = new EventBus()
    }
    return this.instance
  }
}

// ==================== 第二步: AutoIterationEngine 发送事件 ====================
// src/auto-iteration.ts
import { EventBus, AgentEvent } from './event-bus'

export class AutoIterationEngine {
  private eventBus = EventBus.getInstance()

  private async runIteration() {
    const iterationId = this.iterationCount

    // 🔔 发出迭代开始事件
    this.eventBus.emit(AgentEvent.ITERATION_STARTED, {
      iterationId,
      timestamp: new Date(),
      requirement: this.requirement
    })

    try {
      // Phase 1: 产品经理
      this.eventBus.emit(AgentEvent.AGENT_STARTED, {
        iterationId,
        agent: 'product-manager',
        phase: 'analysis'
      })

      const result = await this.productManager.executeAndCollect(...)

      this.eventBus.emit(AgentEvent.AGENT_COMPLETED, {
        iterationId,
        agent: 'product-manager',
        result
      })

      // ... 其他 phases

      // 🔔 迭代完成
      this.eventBus.emit(AgentEvent.ITERATION_COMPLETED, {
        iterationId,
        status: 'success',
        duration: Date.now() - startTime
      })

    } catch (error) {
      this.eventBus.emit(AgentEvent.ITERATION_FAILED, {
        iterationId,
        error: String(error)
      })
    }
  }
}

// ==================== 第三步: Dashboard 监听并广播 ====================
// src/dashboard/services/realtime.service.ts
import { EventBus, AgentEvent } from '../../event-bus'

export class RealtimeService {
  private eventBus: EventBus

  constructor(logger: any) {
    this.eventBus = EventBus.getInstance()
    this.setupEventListeners()
  }

  private setupEventListeners() {
    // 监听迭代事件并广播到 WebSocket
    this.eventBus.on(AgentEvent.ITERATION_STARTED, (data) => {
      this.broadcast('iteration.started', data)
    })

    this.eventBus.on(AgentEvent.AGENT_PROGRESS, (data) => {
      this.broadcast('agent.progress', data)
    })

    this.eventBus.on(AgentEvent.SYSTEM_METRICS, (data) => {
      this.broadcast('system.metrics', data)
    })
  }

  private broadcast(event: string, data: any) {
    const message = JSON.stringify({ event, data })
    this.clients.forEach(ws => {
      if (ws.readyState === WebSocket.OPEN) {
        ws.send(message)
      }
    })
  }
}
```

**预期收益**:
- ✅ 实时数据流打通
- ✅ Dashboard 可见所有迭代状态
- ✅ 解耦 Engine 和 Dashboard
- ✅ 支持多个监听器

