### 🔌 **方案 2: 完善 WebSocket 实时通信** (P0)

#### 前端改进

```typescript
// dashboard/src/utils/websocket-manager.ts
export enum ConnectionState {
  DISCONNECTED = 'disconnected',
  CONNECTING = 'connecting',
  CONNECTED = 'connected',
  RECONNECTING = 'reconnecting',
  ERROR = 'error'
}

export class WebSocketManager {
  private ws: WebSocket | null = null
  private reconnectTimer: any = null
  private heartbeatTimer: any = null
  private eventHandlers: Map<string, Function[]> = new Map()

  state = reactive({
    connectionState: ConnectionState.DISCONNECTED,
    reconnectAttempts: 0,
    lastError: null as string | null,
    connected: false
  })

  connect(url = 'ws://localhost:3000/api/ws') {
    if (this.ws?.readyState === WebSocket.OPEN) {
      return
    }

    this.state.connectionState = ConnectionState.CONNECTING

    this.ws = new WebSocket(url)

    this.ws.onopen = () => {
      this.state.connectionState = ConnectionState.CONNECTED
      this.state.connected = true
      this.state.reconnectAttempts = 0

      // 启动心跳
      this.startHeartbeat()

      // 订阅所有频道
      this.send('subscribe', { channel: 'all' })

      console.log('✅ WebSocket connected')
    }

    this.ws.onmessage = (event) => {
      try {
        const { event: eventName, data } = JSON.parse(event.data)

        // 触发事件处理器
        const handlers = this.eventHandlers.get(eventName)
        if (handlers) {
          handlers.forEach(handler => handler(data))
        }
      } catch (err) {
        console.error('Failed to parse message:', err)
      }
    }

    this.ws.onclose = () => {
      this.state.connected = false
      this.state.connectionState = ConnectionState.DISCONNECTED

      // 自动重连
      this.scheduleReconnect()
    }

    this.ws.onerror = (error) => {
      this.state.connectionState = ConnectionState.ERROR
      this.state.lastError = 'Connection error'
    }
  }

  private startHeartbeat() {
    this.heartbeatTimer = setInterval(() => {
      this.send('ping', {})
    }, 30000) // 30秒
  }

  private scheduleReconnect() {
    if (this.reconnectTimer) return

    this.state.connectionState = ConnectionState.RECONNECTING
    this.state.reconnectAttempts++

    const delay = Math.min(1000 * Math.pow(2, this.state.reconnectAttempts), 30000)

    console.log(`🔄 Reconnecting in ${delay}ms (attempt ${this.state.reconnectAttempts})`)

    this.reconnectTimer = setTimeout(() => {
      this.reconnectTimer = null
      this.connect()
    }, delay)
  }

  send(event: string, data: any) {
    if (this.ws?.readyState === WebSocket.OPEN) {
      this.ws.send(JSON.stringify({ event, data }))
    }
  }

  on(event: string, callback: Function) {
    if (!this.eventHandlers.has(event)) {
      this.eventHandlers.set(event, [])
    }
    this.eventHandlers.get(event)!.push(callback)

    // 返回取消订阅函数
    return () => this.off(event, callback)
  }

  off(event: string, callback: Function) {
    const handlers = this.eventHandlers.get(event)
    if (handlers) {
      const index = handlers.indexOf(callback)
      if (index > -1) {
        handlers.splice(index, 1)
      }
    }
  }

  disconnect() {
    if (this.heartbeatTimer) {
      clearInterval(this.heartbeatTimer)
    }
    if (this.reconnectTimer) {
      clearTimeout(this.reconnectTimer)
    }
    if (this.ws) {
      this.ws.close()
      this.ws = null
    }
  }
}

// 单例模式
const wsManager = new WebSocketManager()
export const useWebSocket = () => wsManager
