#### Store 改进

```typescript
// dashboard/src/stores/dashboard.ts
import { defineStore } from 'pinia'
import { ref, computed } from 'vue'
import { useWebSocket, ConnectionState } from '@/utils/websocket-manager'

export const useDashboardStore = defineStore('dashboard', () => {
  const wsManager = useWebSocket()

  // 实时状态
  const currentIteration = ref(null)
  const agentStates = ref<Map<string, any>>(new Map())
  const systemMetrics = ref([])
  const logs = ref([])

  // 连接状态
  const connected = computed(() => wsManager.state.connected)
  const connectionState = computed(() => wsManager.state.connectionState)

  // 初始化
  function init() {
    // 监听迭代事件
    wsManager.on('iteration.started', (data) => {
      currentIteration.value = data
    })

    wsManager.on('iteration.progress', (data) => {
      if (currentIteration.value?.id === data.iterationId) {
        currentIteration.value.progress = data.progress
      }
    })

    wsManager.on('agent.status_changed', (data) => {
      agentStates.value.set(data.agentName, data)
    })

    wsManager.on('system.metrics', (data) => {
      systemMetrics.value.push({
        ...data,
        timestamp: new Date()
      })
      // 只保留最近 100 条
      if (systemMetrics.value.length > 100) {
        systemMetrics.value.shift()
      }
    })

    wsManager.on('log.entry', (data) => {
      logs.value.push(data)
    })

    // 连接
    wsManager.connect()
  }

  // 控制操作
  function startIteration() {
    wsManager.send('control', { command: 'start' })
  }

  function pauseIteration() {
    wsManager.send('control', { command: 'pause' })
  }

  function stopIteration() {
    wsManager.send('control', { command: 'stop' })
  }

  return {
    // 状态
    currentIteration,
    agentStates,
    systemMetrics,
    logs,
    connected,
    connectionState,

    // 方法
    init,
    startIteration,
    pauseIteration,
    stopIteration
  }
})
```

