<script setup lang="ts">
import { ref, computed } from 'vue'
import SvgIcon from '@/components/SvgIcon.vue'
import LogViewer from '@/components/LogViewer.vue'

interface Agent {
  name: string
  type: string
  status: 'idle' | 'running' | 'completed' | 'error'
  progress?: number
  currentTask?: string
  lastResult?: {
    duration: number
    tokens: number
  }
  logs?: Array<{
    timestamp: Date
    level: string
    message: string
  }>
}

const props = defineProps<{
  agent: Agent
}>()

const emit = defineEmits<{
  execute: [name: string]
  stop: [name: string]
}>()

const showLogs = ref(false)

const agentIcon = computed(() => {
  const icons = {
    'product-manager': 'product-manager',
    'architect': 'architect',
    'frontend': 'frontend',
    'backend': 'backend',
    'database': 'database',
    'ui-designer': 'design',
    'tester': 'test',
    'security': 'security',
    'documenter': 'doc',
    'assets': 'assets'
  }
  return icons[props.agent.type] || 'agent'
})

const statusClass = computed(() => {
  return `status-${props.agent.status}`
})

const statusType = computed(() => {
  const types = {
    idle: 'info',
    running: 'warning',
    completed: 'success',
    error: 'danger'
  }
  return types[props.agent.status]
})

const statusText = computed(() => {
  const texts = {
    idle: '空闲',
    running: '运行中',
    completed: '已完成',
    error: '错误'
  }
  return texts[props.agent.status]
})

const progressStatus = computed(() => {
  if (props.agent.progress >= 100) return 'success'
  if (props.agent.progress >= 50) return ''
  return 'exception'
})

function formatDuration(ms: number) {
  const seconds = Math.floor(ms / 1000)
  if (seconds < 60) return `${seconds}秒`
  const minutes = Math.floor(seconds / 60)
  return `${minutes}分${seconds % 60}秒`
}
