<script setup lang="ts">
import { ref, computed, watch, nextTick } from 'vue'
import { Search } from '@element-plus/icons-vue'

interface LogEntry {
  id: string
  timestamp: Date
  level: 'error' | 'warn' | 'info' | 'debug'
  agentName?: string
  message: string
}

const props = defineProps<{
  logs: LogEntry[]
  agentName?: string
}>()

const searchKeyword = ref('')
const selectedLevel = ref('all')
const autoScroll = ref(true)
const logContainer = ref<HTMLElement>()

const filteredLogs = computed(() => {
  let logs = props.logs

  // 按级别过滤
  if (selectedLevel.value !== 'all') {
    logs = logs.filter(log => log.level === selectedLevel.value)
  }

  // 按关键词搜索
  if (searchKeyword.value) {
    const keyword = searchKeyword.value.toLowerCase()
    logs = logs.filter(log => 
      log.message.toLowerCase().includes(keyword)
    )
  }

  // 只显示最近 500 条
  return logs.slice(-500)
})

function formatTime(timestamp: Date) {
  return new Date(timestamp).toLocaleTimeString('zh-CN')
}

function highlight(message: string) {
  if (!searchKeyword.value) return message

  const regex = new RegExp(`(${searchKeyword.value})`, 'gi')
  return message.replace(regex, '<mark>$1</mark>')
}

function clearLogs() {
  emit('clear')
}

function exportLogs() {
  const content = filteredLogs.value
    .map(log => {
      const time = formatTime(log.timestamp)
      const level = log.level.toUpperCase()
      const agent = log.agentName ? `[${log.agentName}]` : ''
      return `${time} [${level}] ${agent} ${log.message}`
    })
    .join('\n')

  const blob = new Blob([content], { type: 'text/plain' })
  const url = URL.createObjectURL(blob)
  const a = document.createElement('a')
  a.href = url
  a.download = `logs-${Date.now()}.txt`
  a.click()
  URL.revokeObjectURL(url)
}

function handleScroll() {
  if (!logContainer.value) return
  const { scrollTop, scrollHeight, clientHeight } = logContainer.value
  // 如果用户向上滚动,暂停自动滚动
  autoScroll.value = scrollTop + clientHeight >= scrollHeight - 50
}

// 自动滚动到底部
watch(() => props.logs.length, async () => {
  if (autoScroll.value) {
    await nextTick()
    logContainer.value?.scrollTo({
      top: logContainer.value.scrollHeight,
      behavior: 'smooth'
    })
  }
})

const emit = defineEmits<{
